#!/usr/bin/env node
// Reads node_modules/@letta-ai/letta-code/letta.js and writes its content as a
// base64 string into agent/.generated/letta-cli-content.ts. The eve/Nitro
// bundler (Rolldown) does not honor Vite's `?raw` for package files, and
// Vercel's experimentalServices for eve does not install externalized packages
// into the function's runtime node_modules, so we ship the CLI inlined.
//
// Run via `prepare` in package.json (so it runs after `bun install` for local
// dev) and as a prefix in the Vercel `eve` service's buildCommand. Idempotent:
// skipped when the generated file is already up to date with the source.

import { readFileSync, writeFileSync, mkdirSync, statSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { createHash } from "node:crypto";

const projectRoot = resolve(dirname(new URL(import.meta.url).pathname), "..");
const source = resolve(projectRoot, "node_modules/@letta-ai/letta-code/letta.js");
const target = resolve(projectRoot, "agent/.generated/letta-cli-content.ts");

let sourceStat;
try {
  sourceStat = statSync(source);
} catch (err) {
  if (err.code === "ENOENT") {
    console.log(
      `[inline-letta-cli] source not found at ${source}; skipping (likely a clean checkout before \`bun install\`)`,
    );
    process.exit(0);
  }
  throw err;
}

const content = readFileSync(source, "utf8");
const sourceHash = createHash("sha256").update(content).digest("hex");
const encoded = Buffer.from(content, "utf8").toString("base64");

// Skip if the existing file matches.
try {
  const existing = readFileSync(target, "utf8");
  if (existing.includes(`sourceSha256: "${sourceHash}"`)) {
    console.log(`[inline-letta-cli] up to date (sha256=${sourceHash.slice(0, 12)}…)`);
    process.exit(0);
  }
} catch {
  // file doesn't exist yet — proceed
}

mkdirSync(dirname(target), { recursive: true });
writeFileSync(
  target,
  `// AUTO-GENERATED by scripts/inline-letta-cli.mjs. Do not edit.
// Source: node_modules/@letta-ai/letta-code/letta.js
// sourceSha256: "${sourceHash}"
// sourceBytes: ${content.length}
export const LETTA_CLI_SOURCE_BASE64: string =
  ${JSON.stringify(encoded)};
`,
  "utf8",
);

console.log(
  `[inline-letta-cli] wrote ${target} (${content.length} bytes → ${encoded.length} base64 chars, sha256=${sourceHash.slice(0, 12)}…)`,
);
